// src/components/DiscountChart.js
import React, { useEffect, useState } from 'react';
import { supabase } from './supabaseClient'; // Ensure supabaseClient.js is set up correctly
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ReferenceLine, ResponsiveContainer
} from 'recharts';

function DiscountChart() {
  const [data, setData] = useState([]);

  //   // Use static data for testing
  // useEffect(() => {
  //   const formattedData = [
  //     { day: 881, discount: 1.0, backingValue: 1.0 },
  //     { day: 997, discount: 2.0, backingValue: 1.1 },
  //     { day: 1113, discount: 1.5, backingValue: 1.2 },
  //     { day: 1229, discount: 1.3, backingValue: 1.3 },
  //     { day: 1345, discount: 1.4, backingValue: 1.4 },
  //     { day: 1461, discount: 1.5, backingValue: 1.5 },
  //     { day: 1577, discount: 1.2, backingValue: 1.6 },
  //     { day: 1693, discount: 1.3, backingValue: 1.7 },
  //   ];

  //   // Set static data to the state
  //   setData(formattedData);
  // }, []);

  useEffect(() => {
    const fetchData = async () => {
      const { data, error } = await supabase.from('PLS - DiscountCharts').select('*');
      if (error) {
        console.error('Error fetching data:', error);
      } else {
        console.log('Fetched data:', data); // Check what data is returned
        const formattedData = data.map((item) => ({
          day: item.Day,
          discount: parseFloat(item['Discount/Premium']),
          backingValue: parseFloat(item['Backing Value']),
        }));
        console.log('Formatted data:', formattedData); // Log formatted data here
        setData(formattedData);
      }
    };
    fetchData();
  }, []);

  return (
    <ResponsiveContainer width="100%" height={500}>
       <h2 style={{ textAlign: 'left', color: '#666', fontSize: '24px', marginBottom: '20px', marginLeft: '40px'}}>
        pMaxi <span style={{ backgroundColor: '#4285F4', color: 'white', borderRadius: '50%', padding: '2px 8px', marginLeft: '5px' }}>M</span>
      </h2>
      <LineChart
        width={800}
        height={400}
        data={data}
      >
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="day" />
        <YAxis domain={[0, 2.5]} ticks={[0, 0.5, 1, 1.5, 2, 2.5]}/>
        <Tooltip 
            contentStyle={{ backgroundColor: '#fff', border: '1px solid #ccc 8px' }}
            labelStyle={{ color: '#666' }}
            itemStyle={{ color: '#666' }}
          />
        <Legend />
        <Line type="monotone" dataKey="discount" name="Δ Discount/Premium in HEX" dot={false} strokeWidth={2} stroke="#8884d8" />
        <Line type="monotone" dataKey="backingValue" name="Backing Value (Principle + Yield)" dot={false }strokeWidth={2} stroke="#82ca9d" />
        <ReferenceLine 
            x={1255 - 881} 
            stroke="#FBBC05" 
            strokeDasharray="3 3"
            label={{ 
              value: 'PulseChain launch', 
              position: 'top', 
              fill: '#FBBC05', 
              fontSize: 12 
            }} 
          />
      </LineChart>
    </ResponsiveContainer>
  );
}

export default DiscountChart; // Make sure this line is at the top level
